mapper.insert:
INSERT INTO scenario_authoring_job (
    id, project_id, source_discovery_id, correlation_id, idempotency_key, status,
    input_jsonb, provider_policy_jsonb, provider_trace_jsonb, candidates_jsonb,
    validation_jsonb, provenance_jsonb, failure_jsonb, created_by, expires_at
) VALUES (
    #{id}, #{projectId}, #{sourceDiscoveryId}, #{correlationId}, #{idempotencyKey}, #{status},
    CAST(#{inputJsonb} AS jsonb), CAST(#{providerPolicyJsonb} AS jsonb), CAST(#{providerTraceJsonb} AS jsonb), CAST(#{candidatesJsonb} AS jsonb),
    CAST(#{validationJsonb} AS jsonb), CAST(#{provenanceJsonb} AS jsonb), CAST(#{failureJsonb} AS jsonb), #{createdBy,jdbcType=OTHER}, #{expiresAt}
)
